function Marketplace(n){var i=this,u=$("#"+n);this.tabID=n,this.updateMarginDecimal=function(n){var i=$(n).parent().parent().find("[name='marginValue']"),u=$(n).val();i.removeClass("inputnumber").addClass("inputdecimal"),1==u?i.unbind("blur").bind("blur",function(n){inputNumberOnBlur($(this))}):i.unbind("blur").bind("blur",function(n){inputNumberOnBlur($(this),2)}),i.blur()},this.updateDiscDecimal=function(n){var i=$(n).parent().parent().find("[name='discountValue']"),u=$(n).val();i.removeClass("inputnumber").addClass("inputdecimal"),1==u?i.unbind("blur").bind("blur",function(n){inputNumberOnBlur($(this))}):i.unbind("blur").bind("blur",function(n){inputNumberOnBlur($(this),2)}),i.blur()},this.updatePriceType=function(n){1==n.val()?u.find(".isDiscount").hide():u.find(".isDiscount").show()},this.rebindEl=function(){},this.loadOnReady=function(){u.find("[name=selFinalPriceType]").change(function(){i.updatePriceType($(this))}),u.find("[name=selFinalPriceType]").change(),i.rebindEl()}}